interface ScannerViewProps {
  scanning: boolean;
  complete: boolean;
  imgSource?: string;
  refPoints?: { x: number; y: number }[];
  dimensions?: {
    hLine?: { x1: number; y1: number; x2: number; y2: number; label: string };
    vLine?: { x1: number; y1: number; x2: number; y2: number; label: string };
    heelLine?: { x1: number; y1: number; x2: number; y2: number; label: string };
  };
}

function ScannerView({ scanning, complete, imgSource, refPoints = [], dimensions }: ScannerViewProps) {
  const [dots, setDots] = useState<{ x: number; y: number; id: number }[]>([]);
  const [scanY, setScanY] = useState(0);
  const animRef = useRef(null);
  const rafRef = useRef(null);

  // Spawn reference dots while scanning/complete
  useEffect(() => {
    setDots([]);
    if (!scanning && !complete) return;
    let i = 0;
    const targetPoints = refPoints.length > 0 ? refPoints : REF_POINTS;
    const iv = setInterval(() => {
      if (i >= targetPoints.length) { clearInterval(iv); return; }
      setDots(prev => [...prev, { ...targetPoints[i], id: i }]);
      i++;
    }, 85);
    return () => clearInterval(iv);
  }, [scanning, complete, refPoints]);

  // Scan-line RAF animation
  useEffect(() => {
    if (!scanning) { setScanY(0); return; }
    let y = 0;
    const tick = () => {
      y = (y + 2) % 460;
      setScanY(y);
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [scanning]);

  // Greenish tint filter during scan, cyan during active scan
  const imgFilter = complete
    ? "sepia(0.4) hue-rotate(80deg) saturate(1.4) brightness(0.85)"
    : scanning
    ? "sepia(0.6) hue-rotate(160deg) saturate(1.8) brightness(0.7)"
    : "brightness(0.55) saturate(0.4)";

  return (
    <div style={{ position:"relative", width:"100%", height:"100%", overflow:"hidden" }}>
      {/* Grid overlay */}
      <svg style={{ position:"absolute", inset:0, width:"100%", height:"100%", zIndex:1, pointerEvents:"none" }}
           viewBox="0 0 220 460" preserveAspectRatio="none">
        <defs>
          <filter id="glow"><feGaussianBlur stdDeviation="2" result="b"/>
            <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
          <filter id="glow2"><feGaussianBlur stdDeviation="1.2" result="b"/>
            <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
        </defs>
        {/* grid lines */}
        {Array.from({length:14}).map((_,i)=>(
          <line key={`h${i}`} x1="0" y1={i*36} x2="220" y2={i*36} stroke="#00ff8818" strokeWidth="0.4"/>
        ))}
        {Array.from({length:7}).map((_,i)=>(
          <line key={`v${i}`} x1={i*37} y1="0" x2={i*37} y2="460" stroke="#00ff8818" strokeWidth="0.4"/>
        ))}

        {/* Measurement lines — complete only */}
        {complete && dimensions && <>
          {dimensions.hLine && (
            <>
              <line x1={dimensions.hLine.x1} y1={dimensions.hLine.y1} x2={dimensions.hLine.x2} y2={dimensions.hLine.y2} stroke="#ff4444" strokeWidth="0.8" strokeDasharray="4,3"/>
              <line x1={dimensions.hLine.x1} y1={dimensions.hLine.y1 - 4} x2={dimensions.hLine.x1} y2={dimensions.hLine.y1 + 4} stroke="#ff4444" strokeWidth="0.8"/>
              <line x1={dimensions.hLine.x2} y1={dimensions.hLine.y1 - 4} x2={dimensions.hLine.x2} y2={dimensions.hLine.y1 + 4} stroke="#ff4444" strokeWidth="0.8"/>
              <text x={(dimensions.hLine.x1 + dimensions.hLine.x2)/2} y={dimensions.hLine.y1 - 2} fill="#ff4444" fontSize="6" textAnchor="middle" fontFamily="monospace">{dimensions.hLine.label}</text>
            </>
          )}

          {dimensions.vLine && (
            <>
              <line x1={dimensions.vLine.x1} y1={dimensions.vLine.y1} x2={dimensions.vLine.x2} y2={dimensions.vLine.y2} stroke="#ff4444" strokeWidth="0.8" strokeDasharray="4,3"/>
              <line x1={dimensions.vLine.x1 - 4} y1={dimensions.vLine.y1} x2={dimensions.vLine.x1 + 4} y2={dimensions.vLine.y1} stroke="#ff4444" strokeWidth="0.8"/>
              <line x1={dimensions.vLine.x2 - 4} y1={dimensions.vLine.y2} x2={dimensions.vLine.x2 + 4} y2={dimensions.vLine.y2} stroke="#ff4444" strokeWidth="0.8"/>
              <text x={dimensions.vLine.x1 - 6} y={(dimensions.vLine.y1 + dimensions.vLine.y2)/2} fill="#ff4444" fontSize="6" textAnchor="middle" fontFamily="monospace"
                transform={`rotate(-90,${dimensions.vLine.x1 - 6},${(dimensions.vLine.y1 + dimensions.vLine.y2)/2})`}>{dimensions.vLine.label}</text>
            </>
          )}

          {dimensions.heelLine && (
            <>
              <line x1={dimensions.heelLine.x1} y1={dimensions.heelLine.y1} x2={dimensions.heelLine.x2} y2={dimensions.heelLine.y2} stroke="#ff4444" strokeWidth="0.8" strokeDasharray="3,2"/>
              <text x={(dimensions.heelLine.x1 + dimensions.heelLine.x2)/2} y={dimensions.heelLine.y1 - 2} fill="#ff4444" fontSize="5" textAnchor="middle" fontFamily="monospace">{dimensions.heelLine.label}</text>
            </>
          )}
        </>}

        {/* Reference dots */}
        {dots.map(d => (
          <g key={d.id} filter="url(#glow)">
            <circle cx={d.x} cy={d.y} r="3.5" fill="#00ccff" opacity="0.15"/>
            <circle cx={d.x} cy={d.y} r="1.5" fill="#00ccff" opacity="0.9"/>
            <text x={d.x+3} y={d.y-2} fill="#00ccff99" fontSize="4.5" fontFamily="monospace">{d.id+1}</text>
          </g>
        ))}

        {/* Scan sweep line */}
        {scanning && (
          <rect x="0" y={scanY - 20} width="220" height="40"
            fill="url(#scanGrad)" opacity="0.75"/>
        )}

        {/* Gradient def for scan line */}
        <defs>
          <linearGradient id="scanGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"   stopColor="#00ff88" stopOpacity="0"/>
            <stop offset="50%"  stopColor="#00ff88" stopOpacity="0.55"/>
            <stop offset="100%" stopColor="#00ff88" stopOpacity="0"/>
          </linearGradient>
        </defs>

        {/* Corner brackets */}
        {[
          [[0,0],[22,0],[0,22]], [[198,0],[220,0],[220,22]],
          [[0,438],[0,460],[22,460]], [[198,460],[220,460],[220,438]]
        ].map((pts,i)=>(
          <polyline key={i} points={pts.map(p=>p.join(",")).join(" ")}
            fill="none" stroke="#00ff88" strokeWidth="1.8" opacity="0.7"/>
        ))}
      </svg>

      {/* Real evidence image */}
      <img
        src={imgSource || FOOTPRINT_IMG}
        referrerPolicy="no-referrer"
        alt="Evidência — varredura"
        style={{
          position: "absolute", inset: 0,
          width: "100%", height: "100%",
          objectFit: "contain",
          filter: imgFilter,
          transition: "filter 1s ease",
          zIndex: 0,
        }}
      />

      {/* Idle overlay */}
      {!scanning && !complete && (
        <div style={{
          position:"absolute", inset:0, zIndex:2,
          display:"flex", flexDirection:"column",
          alignItems:"center", justifyContent:"center",
          background:"#050a0899",
          color:"#00ff8840",
        }}>
          <div style={{fontSize:28, marginBottom:8}}>🔎</div>
          <div style={{fontSize:9, letterSpacing:3}}>AQUISIÇÃO ATIVA</div>
        </div>
      )}
    </div>
  );
}

class ForensicAudioController {
  private ctx: AudioContext | null = null;
  private scanInterval: any = null;

  private initCtx() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.ctx.state === "suspended") {
      this.ctx.resume();
    }
    return this.ctx;
  }

  public playStart() {
    try {
      const ctx = this.initCtx();
      const t = ctx.currentTime;
      
      const osc1 = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gainNode = ctx.createGain();

      osc1.type = "sine";
      osc2.type = "sine";

      osc1.frequency.setValueAtTime(360, t);
      osc1.frequency.exponentialRampToValueAtTime(720, t + 0.12);

      osc2.frequency.setValueAtTime(720, t);
      osc2.frequency.exponentialRampToValueAtTime(1080, t + 0.08);

      gainNode.gain.setValueAtTime(0.08, t);
      gainNode.gain.setValueAtTime(0.08, t + 0.08);
      gainNode.gain.exponentialRampToValueAtTime(0.001, t + 0.22);

      osc1.connect(gainNode);
      osc2.connect(gainNode);
      gainNode.connect(ctx.destination);

      osc1.start(t);
      osc2.start(t);
      osc1.stop(t + 0.25);
      osc2.stop(t + 0.25);
    } catch (e) {
      console.warn("Audio error:", e);
    }
  }

  public playTone(freq: number, delay: number, duration: number, volume: number = 0.05) {
    try {
      const ctx = this.initCtx();
      const t = ctx.currentTime;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      
      osc.type = "sine";
      osc.frequency.setValueAtTime(freq, t + delay);
      
      gain.gain.setValueAtTime(0.001, t + delay);
      gain.gain.linearRampToValueAtTime(volume, t + delay + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, t + delay + duration);
      
      osc.connect(gain);
      gain.connect(ctx.destination);
      
      osc.start(t + delay);
      osc.stop(t + delay + duration + 0.05);
    } catch (e) {
      console.warn("Audio tone error:", e);
    }
  }

  public startProcessing() {
    this.stopProcessing();
    try {
      const ctx = this.initCtx();

      const playPulse = () => {
        const t = ctx.currentTime;
        const osc = ctx.createOscillator();
        const filter = ctx.createBiquadFilter();
        const gain = ctx.createGain();

        // Forensic analyzer radar sound ("chirp")
        osc.type = "sine";
        osc.frequency.setValueAtTime(900, t);
        osc.frequency.exponentialRampToValueAtTime(250, t + 0.15);

        filter.type = "lowpass";
        filter.Q.setValueAtTime(6, t);
        filter.frequency.setValueAtTime(1800, t);
        filter.frequency.exponentialRampToValueAtTime(600, t + 0.15);

        gain.gain.setValueAtTime(0.03, t);
        gain.gain.exponentialRampToValueAtTime(0.001, t + 0.15);

        osc.connect(filter);
        filter.connect(gain);
        gain.connect(ctx.destination);

        osc.start(t);
        osc.stop(t + 0.18);

        // Ambient diagnostic sub-hum sound
        const hum = ctx.createOscillator();
        const humGain = ctx.createGain();
        hum.type = "triangle";
        hum.frequency.setValueAtTime(65, t);
        humGain.gain.setValueAtTime(0.02, t);
        humGain.gain.exponentialRampToValueAtTime(0.001, t + 0.25);
        
        hum.connect(humGain);
        humGain.connect(ctx.destination);
        hum.start(t);
        hum.stop(t + 0.28);
      };

      playPulse();
      this.scanInterval = setInterval(playPulse, 400);
    } catch (e) {
      console.warn("Audio processing error:", e);
    }
  }

  public stopProcessing() {
    if (this.scanInterval) {
      clearInterval(this.scanInterval);
      this.scanInterval = null;
    }
  }

  public playSuccess() {
    this.stopProcessing();
    try {
      const ctx = this.initCtx();
      const t = ctx.currentTime;
      
      const playTone = (freq: number, delay: number, duration: number, volume: number = 0.05) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        
        osc.type = "sine";
        osc.frequency.setValueAtTime(freq, t + delay);
        
        gain.gain.setValueAtTime(0.001, t + delay);
        gain.gain.linearRampToValueAtTime(volume, t + delay + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.001, t + delay + duration);
        
        osc.connect(gain);
        gain.connect(ctx.destination);
        
        osc.start(t + delay);
        osc.stop(t + delay + duration + 0.05);
      };

      // F# major / B major elegant micro-melodic chimes for clean success
      playTone(554.37, 0.00, 0.22); // C#5
      playTone(659.25, 0.06, 0.22); // E5
      playTone(830.61, 0.12, 0.22); // G#5
      playTone(1108.73, 0.18, 0.40, 0.06); // C#6
    } catch (e) {
      console.warn("Audio success error:", e);
    }
  }
}
