export function normalizeEvidenceCard(card: EvidenceCard): EvidenceCard {
  if (!card) return card;
  const mode = card.scannerMode || "FOOTPRINT";
  const defaults = DEFAULT_TEMPLATES[mode] || DEFAULT_TEMPLATES.FOOTPRINT;

  const normalizedData: EvidenceResultCustom = {
    id: card.id,
    title: card.data?.title || `${card.label.toUpperCase()} — DETECTED`,
    typeName: card.data?.typeName || defaults.typeName,
    labTech: card.data?.labTech || defaults.labTech,
    equipment: card.data?.equipment || defaults.equipment,
    defaultConfidence: card.data?.defaultConfidence ?? defaults.defaultConfidence,
    parameters: card.data?.parameters || defaults.parameters,
    matches: card.data?.matches || defaults.matches,
    refPoints: card.data?.refPoints || defaults.refPoints,
    dimensions: card.data?.dimensions || defaults.dimensions,
    stages: card.data?.stages || defaults.stages,
    logs: card.data?.logs || defaults.logs,
  };

  let finalImage = card.image;
  if (!finalImage) {
    if (mode === "FOOTPRINT") {
      finalImage = FOOTPRINT_IMG;
    } else if (mode === "DNA") {
      finalImage = DNA_SVG;
    } else if (mode === "DOCUMENT") {
      finalImage = DOC_CONTRACT_SVG;
    } else if (mode === "DIGITAL") {
      finalImage = FINGERPRINT_SVG;
    } else if (mode === "VIDEO") {
      finalImage = VIDEO_CCTV_SVG;
    } else {
      finalImage = "";
    }
  }

  return {
    ...card,
    icon: card.icon || defaults.icon,
    image: finalImage,
    scannerMode: mode,
    data: normalizedData,
  };
}

export const EVIDENCE_CARDS: EvidenceCard[] = RAW_EVIDENCE_CARDS.map(normalizeEvidenceCard);

interface ForensicScannerProps {
  evidence?: EvidenceCard;
  evidenceList?: EvidenceCard[];
  onSelectEvidence?: (card: EvidenceCard) => void;
  scanIntensity?: "fast" | "standard" | "high";
  onIntensityChange?: (intensity: "fast" | "standard" | "high") => void;
  onScanComplete?: (result: EvidenceResultCustom, finalConfidence: number) => void;
}

const adjustConfidence = (base: number, intensity: "fast" | "standard" | "high") => {
  if (intensity === "fast") return Math.max(40, Number((base - 5.4).toFixed(1)));
  if (intensity === "high") return Math.min(100, Number((base + 2.1).toFixed(1)));
  return base;
};

const SuspectAvatar = ({ suspect }: { suspect: any }) => {
  const [currentSrc, setCurrentSrc] = useState<string | undefined>(suspect.image);
  const [useFallback, setUseFallback] = useState<boolean>(!suspect.image);
  const [errored, setErrored] = useState(false);

  const handleError = () => {
    if (suspect.image && currentSrc === suspect.image && !suspect.image.includes("/Fotos/")) {
      const directoryMatch = suspect.image.match(/(Suspeito_\d+)\//);
      if (directoryMatch) {
        const targetDir = directoryMatch[1];
        const nextSrc = suspect.image.replace(`${targetDir}/`, `${targetDir}/Fotos/`);
        setCurrentSrc(nextSrc);
        return;
      }
    }
    if (!errored) {
      setErrored(true);
      setUseFallback(true);
    }
  };

  if (!useFallback && currentSrc) {
    return (
      <div style={{ 
        width: "55px", 
        height: "70px", 
        flexShrink: 0, 
        borderRadius: "3px", 
        overflow: "hidden", 
        border: "1px solid #334155",
        background: "rgba(0,0,0,0.3)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center"
      }}>
        <img
          src={currentSrc}
          alt={suspect.name}
          onError={handleError}
          style={{ width: "100%", height: "100%", objectFit: "cover" }}
          referrerPolicy="no-referrer"
        />
      </div>
    );
  }

  return (
    <span style={{ 
      fontSize: "24px", 
      alignSelf: "center", 
      width: "55px", 
      height: "70px", 
      display: "flex", 
      alignItems: "center", 
      justifyContent: "center",
      background: "rgba(30, 41, 59, 0.4)",
      borderRadius: "3px",
      border: "1px solid #1e293b",
      flexShrink: 0
    }}>
      {suspect.avatar}
    </span>
  );
};

